var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"지금 놀리시는 거죠? 전 살면서 요정을 한 번도 본 적 없는걸요.","JPN":"私のこと、からかってるんですか？　私は人生で一度も妖精なんて見たことありません。","ENG":"You're just messing with me, right? I've never seen a fairy in my life.","TWN":"你在開玩笑吧？我這輩子從沒見過精靈。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"네가 살아남은 이유에 대해, 나는 두 가지 가능성을 생각했어.","JPN":"アナタが生き残った理由について、アタシは二つの可能性を考えたの。","ENG":"I have thought of two possibilities for how you are still alive.","TWN":"關於你能活下來的原因，我想到了二種可能性。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"하나는 네가 악마에게 영혼을 바친 대가로 죽지 않은 것.","JPN":"一つはアナタが悪魔に魂を捧げた対価として死を免れたという説。","ENG":"One is that you offered your soul to the devil in return for immortality.","TWN":"一是你把靈魂獻給了魔鬼，所以沒死。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그리고 또 다른 하나는, 네가 살아있길 바라는 <color=#ffd34c>가능성의 존재</color>가 있다는 것.","JPN":"そしてもう一つは、アナタの生存を願う<color=#ffd34c>可能性の存在</color>がいるという説。","ENG":"The other is that there is an <color=#ffd34c>entity of possibilities</color> that wishes you to live.","TWN":"另一種是，有某個希望你活著的<color=#ffd34c>可能性</color>存在。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"만약 전자가 확실했다면… 난 굳이 널 살려두지 않았을 거야.","JPN":"もし前者だったとしたら……アタシはアナタを生かしておかなかったはずよ。","ENG":"If I was certain of the former... I would not have kept you alive.","TWN":"如果是前者…我就不會留你活到現在。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"으윽…","JPN":"ううっ……","ENG":"Ngh...","TWN":"嗯嗯…"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"하지만 네가 지금까지 보여준 행보는 영혼 없는 인간과는 달랐어.","JPN":"でも、今までアナタが見せてくれた言動は魂のない人間とは違っていたわ。","ENG":"However, the actions you have shown are far from those of a soulless person.","TWN":"你至今的表現不像是失去靈魂的手下。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"오히려, 우릴 도우러 온 구원자에 가까웠지.","JPN":"むしろ、アタシたちを助けにきた救世主のようだった。","ENG":"As a matter of fact, you are closer to a savior who has come to help us.","TWN":"反而更像是來幫助我們的救贖者。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"구원자…","JPN":"救世主……","ENG":"A savior…","TWN":"救贖者…"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"요정님이 꿈에서 나에게 말씀하셨단다.","JPN":"妖精さんが夢に出てきてお話ししてくれたの。","ENG":"A fairy came into my dreams and said this to me.","TWN":"精靈在夢中悄悄對我說。"},"stage":{"bg":"WHITE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"우리와 다르게… 너에겐 빛이 있다고 했어.","JPN":"普通の人とは違い……あなたには光があるって。","ENG":"\\"Unlike me... there is light within you.","TWN":"你和我們不同…你有光。"},"stage":{"bg":"WHITE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"아무리 절망적인 상황에서도… 모든 걸 이겨낼 빛이.","JPN":"どんなに絶望的な状況になっても……すべてに打ち勝てる光が。","ENG":"No matter how tough it gets... your light will overcome it all.\\"","TWN":"無論多麼絕望的情況…都能克服的光。"},"stage":{"bg":"WHITE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"제가 살아있는 게, 제가 지금껏 찾지 못한 요정 덕분일지도 모른다니.","JPN":"私が生きているのが、今まで見つけられなかった妖精のおかげかもしれないなんて。","ENG":"You think that I'm alive because of a fairy that I haven't been able to find?","TWN":"我能活下來，可能是因為我沒找到的那個精靈？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"만약 그게 사실이라면… 요정이 저에게 뭘 남겨준 거죠?","JPN":"もしそれが本当なら……妖精は私に何を残してくれたのでしょう？","ENG":"If that's true... then what did this fairy leave me with?","TWN":"如果這是真的…那精靈給我留下了什麼？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"글쎄.","JPN":"さあね。","ENG":"Who knows?","TWN":"不清楚。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 기적의 형태는 네가 가진 무기일 수도, 다른 것일 수도 있어.","JPN":"その奇跡の形はアナタが持っている武器か、それとも別の何かかもしれないわ。","ENG":"A miracle may take form as your weapon, or perhaps something else.","TWN":"那奇蹟的形態可能是你手中的武器，也可能是其他東西。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그게 뭔지 아는 존재가 있다면, 오직 너와 그 요정뿐일 거야.","JPN":"それが何なのか知っているとしたら、それはアナタとその妖精だけでしょう。","ENG":"If anyone knows of its existence, it will be you and the fairy.","TWN":"知道那是什麼的，只有你和那個精靈。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"하지만, 그게 무엇인지 모른다고 해서 조급할 필요는 없어.","JPN":"でも、それがわからないからといって焦る必要はないの。","ENG":"Yet, there is no need to be impatient about not knowing what it is.","TWN":"不過，不知道也不用著急。"},"stage":{"bg":"HALL","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"기적이라는 건 언제나처럼 그 자리에 있다가, 어둠 속에서 불현듯 빛나는 법이거든.","JPN":"奇跡というのはいつもそこにあって、闇の中で突然光るものよ。","ENG":"Miracles are always in place, but suddenly shine bright in times of darkness.","TWN":"奇蹟總是存在的，它會在黑暗中突然閃耀。"},"stage":{"bg":"HALL","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"정말 이래도 괜찮나요…? 많이 바쁘시다고 들었는데.","JPN":"本当にいいんですか……？　とても忙しいって聞きましたけど。","ENG":"Are you sure about this...? I heard you were extremely busy.","TWN":"這樣真的沒關係嗎…？聽說你很忙。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"사양할 것 없어.","JPN":"遠慮することないわ。","ENG":"No need to decline my offer.","TWN":"不用客氣。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"같이 술을 못 마시니까, 한 번쯤 제대로 된 식사라도 대접해주고 싶었거든.","JPN":"一緒にお酒は飲めないから、一度くらいちゃんとおごってあげたかったの。","ENG":"Since we cannot drink together, I wanted to at least treat you to a proper meal.","TWN":"因為不能一起喝酒，所以至少想請你吃頓像樣的飯。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"으…","JPN":"うう……","ENG":"Err...","TWN":"呃…"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"죄송해요. 제가 술을 못 마셔서…","JPN":"すみません。私、ゲコで……","ENG":"I'm sorry that I can't drink...","TWN":"非常抱歉…"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"일일이 사과할 필요없어.","JPN":"そんなことで謝らないで。","ENG":"No need to apologize for everything.","TWN":"沒必要什麼都道歉。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"자, 식기 전에 먹으렴.","JPN":"さあ、冷めないうちに食べなさい。","ENG":"Now, eat up before it gets cold.","TWN":"來，趁熱吃吧。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"이건… 오믈렛이네요.","JPN":"これは……オムレツですね。","ENG":"This is... an omelet.","TWN":"這是…蛋包飯欸。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그루터기에서 닭을 키우는 모습은 못 본 것 같은데.","JPN":"切り株で鶏を飼っている人なんて見たことありませんよ？","ENG":"But I didn't see any chickens back at the Stump.","TWN":"我好像沒見過木墩上有養雞。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"맞아. 닭이 아니라 이 녀석이 낳은 거야.","JPN":"そうよ。鶏じゃなくて、この子が産んだの。","ENG":"That is right. It is not a chicken's but this creature's.","TWN":"沒錯，所以不是雞下的，是牠下的。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_OWL","text":{"KOREA":"후?","JPN":"ふう？","ENG":"Hoot?","TWN":"咕？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWING_SMALL"},{"id":"L44_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"엑.","JPN":"えっ。","ENG":"Eck.","TWN":"唔？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그래도 괜찮나요…? 알을 주인 앞에서 먹어버려도…?","JPN":"いいんですか……？　タマゴを本人の前で食べちゃっても……","ENG":"Is it okay...? To eat an egg in front of the mother...?","TWN":"這樣真的沒關係嗎…在主人面前吃掉牠的蛋…？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"무정란이니 괜찮아.","JPN":"無精卵だから大丈夫。","ENG":"It is unfertilized, so it is fine.","TWN":"是無精蛋，沒關係的。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"녀석도 영리해서 그 정돈 분간할 줄 알거든.","JPN":"この子は頭がいいから、そのくらい理解しているわ。","ENG":"She is intelligent enough to know the difference.","TWN":"牠也很聰明，能分辨這些。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그래도 누구 선물인지 알아버린 이상, 인사는 나누는 편이 좋겠지?","JPN":"でも誰からのプレゼントなのかわかったのなら、お礼はするべきよね。","ENG":"But knowing whose gift this is, shouldn't you at least say thank her?","TWN":"不過既然知道是誰的禮物，還是打個招呼比較好吧？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"이, 일용할 양식을 저에게 베풀어주셔서 감사합니다! 부엉이님!","JPN":"ひ、日々の糧を私に与えてくれてありがとうございます！　ミミズクさん！","ENG":"Th-thank you for providing me with this nourishment, Ms. Owl!","TWN":"感…感謝貓頭鷹賜予我豐盛的食物！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_OWL","text":{"KOREA":"후-","JPN":"ふー。","ENG":"Hoot!","TWN":"咕—"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_OWL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_SWING_SMALL"},{"id":"L3_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그런데 모르가나가 안 보이네요. 같이 안 먹으려나?","JPN":"そういえば、モルガナがいませんね。一緒に食べないのかな？","ENG":"Where's Morgana? Isn't she eating with us?","TWN":"不過莫甘娜不知道去哪了？她不一起吃嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"후후. 너도 알다시피 그 애가 엄청 눈치를 살피는 편이잖니?","JPN":"ふふ。アナタも知ってると思うけど、あの子は人の目を気にするタイプでしょう？","ENG":"Fu fuu. As you know, she is very timid.","TWN":"呵呵，你知道那孩子很敏感的吧？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"내 요리를 돕겠다고 실수로 알을 깨먹은 적이 있어서 말이야.","JPN":"アタシの料理を手伝うって言って、失敗してタマゴを割ってしまったことがあるの。","ENG":"And she once made the mistake of breaking an egg while trying to help me cook.","TWN":"她曾經想幫我做飯，結果不小心把蛋打破了。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"아하하…","JPN":"あはは……","ENG":"Ah hah hah...","TWN":"哈哈哈…"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"모르가나는 강한 아이지만, 마음은 정말 여리다니까요.","JPN":"モルガナは強い子ですけど、心は優しいですから。","ENG":"Morgana is strong, but her heart's still frail.","TWN":"莫甘娜雖然外表很強，但內心卻非常柔軟。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그러게나 말이야.","JPN":"そうね。","ENG":"I know.","TWN":"是啊。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"이 오믈렛… 엄청 부드럽고 맛있네요.","JPN":"このオムレツ……とても柔らかくて美味しいですね。","ENG":"This omelet... it's so soft and delicious.","TWN":"謝謝…蛋包…非常柔軟…非常美味。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"알아. 내 솜씨니까.","JPN":"当たり前よ。アタシが作ったんだから。","ENG":"I know. I made it, after all.","TWN":"我知道，這可是我的手藝。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"흑…","JPN":"うっ……","ENG":"*Sniffle*","TWN":"呵…"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"흐윽…","JPN":"ううっ……","ENG":"*Sob*","TWN":"呵呵…"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"우리가 잠들어 있을 때에도.","JPN":"我々が眠りについる間にも。","ENG":"Even when we are in slumber.","TWN":"就算是我等在沉睡時。"},"stage":{"bg":"SKY","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"세계는 종말을 향해 다가가고 있다.","JPN":"世界は終末に向かいつつある。","ENG":"The end of the world is nigh.","TWN":"世界也正在走向終結。"},"stage":{"bg":"SKY","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"그 오랜 역사가 무색하게도 과거는 사라지고 만다.","JPN":"長い歴史なんて無意味だというように、過去は消えてしまう。","ENG":"Despite the long-standing history, the past will disappear.","TWN":"再悠久的歷史也有黯然失色的一天，過去終將消逝。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"어젯밤의 찬란했던 문명은 동이 트면 차가운 흔적으로만 남는다.","JPN":"昨夜の輝かしい文明は、夜が明ければ冷たい痕跡として残る。","ENG":"A brilliant civilization is left in cold ruins as dawn breaks.","TWN":"昨夜輝煌燦爛的文明，破曉之時也只剩下了冰冷的痕跡。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"그런 광경이 익숙하게 다가올 정도로, 시대는 종말에 가까워지고 있었다.","JPN":"そんな光景が身近に感じられるくらいに、時代は終末に近づいていた。","ENG":"As the landscape of it all becomes all too familiar, the era of the end also approaches.","TWN":"這樣的景象已經變得司空見慣，時代正接近終結。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"그렇기에, 누군가는 약속해야만 했다.","JPN":"だから、誰かが約束する必要があった。","ENG":"So, someone had to make a promise.","TWN":"因此，有人必須做出承諾。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"이 세상엔 아직 희망이 남아있노라고.","JPN":"この世にはまだ希望が残っているのだと。","ENG":"That there is still hope left in this world.","TWN":"在這個世界上仍然存在著希望。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"루… 분명 충격 받았겠지.","JPN":"ルー……きっとショックだったよね。","ENG":"I'm sure Lugh... was shocked by it all.","TWN":"露…她肯定受到了很大的衝擊。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"어쩌면, 지금쯤 울고 있을지도 몰라.","JPN":"もしかしたら、今頃泣いてるかも。","ENG":"She might be crying right about now.","TWN":"說不定現在正在偷偷抹眼淚…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"돌아가서 위로해줘야하나?","JPN":"戻って慰めてあげたほうがいいかな？","ENG":"Should I go back and comfort her?","TWN":"要不要回去安慰她呢？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아니면 역시… 아무것도 못 들은 척하는 게 좋을지도.","JPN":"それともやっぱり……何も知らないふりをした方がいいのかも。","ENG":"Or maybe... it's better to pretend that I didn't hear anything.","TWN":"還是說…裝作什麼都沒聽到比較好。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"으으으음…!!","JPN":"ううううーん……！！","ENG":"Mmm...!!","TWN":"呃呃呃嗯…！！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐야? 사람들이잖아?","JPN":"何だろう？　あの人たち。","ENG":"Huh? What are people doing here?","TWN":"怎麼回事？那麼多人？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"저긴 멀린의 집무실 방향인데… 왜 다들 화가 나있는 것 같지?","JPN":"あそこはマーリンの執務室だけど……なんだかみんな怒ってるみたい。","ENG":"This is in the direction of Merlin's office... and why do they look all angry?","TWN":"那邊是梅林的辦公室方向…為什麼大家看起來都很生氣？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"거기 잠깐…!","JPN":"あの、ちょっと……！","ENG":"Hey...!","TWN":"喂，你等等…！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"으븝?!","JPN":"ううっ！？","ENG":"Mmph?!","TWN":"呃啊？！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"쉿. 조용히.","JPN":"しっ、静かに。","ENG":"Hush, be quiet.","TWN":"噓，小姐，請安靜。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"키안…?","JPN":"キアン……？","ENG":"Kian...?","TWN":"奇恩爺爺…？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"방금 전, 누군가 반역자를 잡아야 한다며 사람들을 모으고 있더군요.","JPN":"先ほど、誰かが反逆者を捕まえろと言って人を集めていました。","ENG":"Someone is gathering the people and saying that they should capture the traitor.","TWN":"剛才，有人說要抓叛徒，正在召集人手。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐?","JPN":"え？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그럼 루가 위험하잖아! 이렇게 숨을 게 아니라 당장 가서 도와야지!","JPN":"じゃあ、ルーが危ない！　早く行って助けてあげないと！","ENG":"Then Lugh's in danger! We should go help her, not hide like this!","TWN":"那露有危險了！不能這樣躲著，我要趕緊去幫忙！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"어설픈 바람은 들불을 키울 뿐입니다.","JPN":"中途半端な風は野火を大きくするだけです。","ENG":"Fire will only spread quickly if not put out correctly.","TWN":"輕舉妄動只會讓事情變得更複雜。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"제사장께서 함께 계실 테니, 우선 침착하게 지켜보도록 하죠.","JPN":"祭祀長がご一緒のはずですから、まずは落ち着いて見守りましょう。","ENG":"She is with the High Priest, so we should calmly see where this goes.","TWN":"露和祭司長在一起，我們先冷靜觀察觀察。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_NULL","text":{"KOREA":"주민들이 몰려오고 있습니다! 제사장님!","JPN":"住民が押し寄せて来ています！　祭祀長！","ENG":"The villagers are all gathering here, High Priest!","TWN":"居民們朝這裡聚過來了！祭司長！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_NULL","text":{"KOREA":"다들 반역자를 내놓으라고, 혈안이 되어있어요!","JPN":"みんな反逆者を出せと血眼になって探してます！","ENG":"They are all demanding that you hand over the traitor!","TWN":"大家都像瘋了一樣地在找叛徒！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"결국 올 것이 온 모양이네.","JPN":"結局はこうなってしまうのね。","ENG":"It seems that it has finally come to this.","TWN":"最終還是來了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"넌 뒷문으로 나가렴. 이쪽은 내가 해결할 테니까.","JPN":"アナタは裏門から出なさい。こっちはアタシが解決するわ。","ENG":"Go out through the back door. I will take care of them.","TWN":"你從後門出去，這邊我來解決。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"아뇨. 저도 함께 가겠어요.","JPN":"いいえ。私も一緒に行きます。","ENG":"No, I'll go with you.","TWN":"不，我也要一起去。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"도망치는 걸론 아무것도 해결되지 않으니까요.","JPN":"逃げるだけでは何も解決できませんから。","ENG":"I've learned that running away doesn't solve anything.","TWN":"逃跑不能解決任何問題。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"좋은 마음가짐이지만, 이번엔 내 말을 듣도록 해.","JPN":"その度胸は認めるけれど、今回はアタシの言うことを聞きなさい。","ENG":"Though I admire your spirit, listen to me this time.","TWN":"你心意是好的，但這次聽我的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"너한텐 따로 부탁할 일이 있거든.","JPN":"アナタには別に頼みたいことがあるの。","ENG":"I have something else to ask of you.","TWN":"我有件事要特別拜託你。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};